const activeMembers = r1.uniqueSubscribers || 0;

const r2 = await this.helpers.httpRequest({ method: 'GET', url: 'https://api.brevo.com/v3/contacts/lists/9', headers });
const audience = r2.uniqueSubscribers || 0;

