const delivered = r3.delivered || 0;
const opens = r3.uniqueOpens || 0;
const openRate = delivered > 0 ? Math.round((opens / delivered) * 100) : 0;
const clicks = r3.uniqueClicks || 0;
const unsubs = r3.unsubscribed || 0;

const today = new Date().toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });
const subject = 'FSY Rapport Hebdo - ' + today;

